<template>
    <Head>
        <title>პაროლის შეცვლა</title>
    </Head>

    <div class="bg-white flex flex-col justify-evenly mx-3 sm:mx-auto shadow-lg rounded-xl border border-slate-200 mt-8 w-[250px] sm:w-[450px] h-[400px]">
        <form @submit.prevent="resetPassword" class="flex flex-col p-8 gap-6 self-center">
            <div class="flex flex-col space-y-5">
                <div class="self-center text-2xl font-semibold">ახალი პაროლი</div>
            </div>
            <Message
                v-if="$page.props.flash.message"
                pt:content:class="flex flex-col"
                pt:text:class="text-justify"
                pt:icon:class="mb-4 text-3xl"
                severity="success"
                icon="pi pi-check-circle"
            >
                {{ $page.props.flash.message }}
            </Message>

            <!-- Form Validation Errors -->
            <div v-if="Object.keys(errors).length > 0"
                 class="mb-6 bg-red-50 border border-red-200 rounded-lg p-4 flex justify-between">
                <div class="text-red-600 text-sm">
                    <p v-for="(error, key, index) in errors" :key="key">{{index+1}}) {{ error }}</p>
                </div>
                <i class="pi pi-exclamation-circle text-red-400 mr-3 mt-0.5"></i>
            </div>

            <FloatLabel variant="on">
                <InputText id="phone" v-model="form.phone" :invalid="form.errors.phone" fluid/>
                <label for="phone">ტელეფონი</label>
            </FloatLabel>

            <FloatLabel variant="on">
                <Password
                    :feedback="false"
                    toggleMask
                    pt:maskIcon:class="z-10"
                    pt:unmaskIcon:class="z-10"
                    inputClass="w-full rounded-md focus:shadow-none"
                    :invalid="form.errors.password"
                    class="w-full"
                    v-model="form.password"
                    inputId="password"
                />
                <label for="password">ახალი პაროლი</label>
            </FloatLabel>

            <FloatLabel variant="on">
                <Password
                    toggleMask
                    pt:maskIcon:class="z-10"
                    pt:unmaskIcon:class="z-10"
                    :feedback="false"
                    inputClass="w-full rounded-md focus:shadow-none"
                    :invalid="form.errors.password_confirmation"
                    class="w-full"
                    v-model="form.password_confirmation"
                    inputId="password_confirmation"
                />
                <label for="password_confirmation">გაიმეორე ახალი პაროლი</label>
            </FloatLabel>

            <div class="flex xs:flex-col gap-2 sm:justify-between sm:items-center">
                <Button
                    :disabled="form.processing"
                    type="submit"
                    class="custom-button w-full"
                    :label="form.processing ? 'გთხოვ დაიცადო...' : 'დადასტურება'"
                    size="medium"
                    :icon="form.processing ? 'pi pi-spin pi-spinner' :''"
                />
            </div>
        </form>
    </div>
</template>

<script setup>
import {Head, useForm} from '@inertiajs/vue3';
const props = defineProps(['errors']);

const form = useForm({
    phone: null,
    password: null,
    password_confirmation: null,
})

async function  resetPassword(){
    form.post(route('forgot-password.reset'), {
        onSuccess: (page) => {
            form.reset();
        },
        onError: (error) => {

        }
    })
}

</script>

